import base64
import os


def base64_to_image(base64_str, output_path="output_image.jpg"):
    """
    将Base64编码的图片字符串还原为图片文件

    Args:
        base64_str (str): 图片的Base64编码字符串（可带data URL前缀）
        output_path (str): 输出图片的路径和文件名，默认保存为output_image.jpg

    Returns:
        bool: 成功返回True，失败返回False
    """
    try:
        # 1. 处理Base64字符串前缀（如果有）
        if "," in base64_str:
            # 分离前缀和真正的Base64编码部分
            base64_str = base64_str.split(",")[1]

        # 2. 解码Base64字符串为二进制数据
        image_data = base64.b64decode(base64_str)

        # 3. 确保输出目录存在
        output_dir = os.path.dirname(output_path)
        if output_dir and not os.path.exists(output_dir):
            os.makedirs(output_dir)

        # 4. 将二进制数据写入文件
        with open(output_path, "wb") as f:
            f.write(image_data)

        print(f"图片已成功还原并保存到: {os.path.abspath(output_path)}")
        return True

    except base64.binascii.Error as e:
        print(f"Base64解码失败: {e}")
        return False
    except Exception as e:
        print(f"处理过程中出错: {e}")
        return False


# 示例使用
if __name__ == "__main__":
    # 替换为你的Base64编码字符串
    test_base64 = "data:image/jpeg;base64,"

    # 调用函数还原图片，可指定输出路径，如：base64_to_image(test_base64, "my_image.png")
    base64_to_image(test_base64)